mapper.select:
SELECT *
FROM sprout_tag t1
WHERE t1.tag_id = #{tagId}

mapper.insert:
INSERT INTO sprout_tag (
    tag_name
  , tag_detail
  , tag_color
  , tag_sort_order
  , update_at
) VALUE (
    #{tagName}
  , #{tagDetail}
  , #{tagColor}
  , #{tagSortOrder}
  , #{updateAt}
)

mapper.update:
UPDATE sprout_tag
SET
    tag_name = #{tagName}
  , tag_detail = #{tagDetail}
  , tag_color = #{tagColor}
  , tag_sort_order = #{tagSortOrder}
  , update_at = #{updateAt}
WHERE
  tag_id = #{tagId}

UPDATE sprout_tag
SET tag_sort_order = #{tagSortOrder}
WHERE tag_id = #{tagId}

mapper.insert:
INSERT INTO sprout_item_tag (
    item_id
  , tag_id
) VALUES (
    #{itemId}
  , #{tagId}
)

mapper.delete:
DELETE FROM sprout_item_tag
WHERE
  item_id = #{itemId}
  AND tag_id = #{tagId}
